import{_ as e,c as o,o as i,ag as a}from"./chunks/framework.DD2hp6gW.js";const u=JSON.parse('{"title":"Radio Buttons Field","description":"","frontmatter":{},"headers":[],"relativePath":"fields/radio.md","filePath":"fields/radio.md","lastUpdated":null}'),n={name:"fields/radio.md"};function l(s,t,r,d,c,h){return i(),o("div",null,t[0]||(t[0]=[a('<h1 id="radio-buttons-field" tabindex="-1">Radio Buttons Field <a class="header-anchor" href="#radio-buttons-field" aria-label="Permalink to &quot;Radio Buttons Field&quot;">​</a></h1><p>The <strong>Radio</strong> field allows customers to select exactly one option from a list, with all choices visible at once on the product page. Unlike a dropdown, customers can see every available option without clicking.</p><h2 id="common-use-cases" tabindex="-1">Common Use Cases <a class="header-anchor" href="#common-use-cases" aria-label="Permalink to &quot;Common Use Cases&quot;">​</a></h2><ul><li>Selecting a primary color when only a few options exist</li><li>Choosing between standard or expedited processing</li><li>Picking a warranty tier (None, 1-Year, 3-Year)</li><li>Selecting a product variant visually</li></ul><h2 id="field-settings" tabindex="-1">Field Settings <a class="header-anchor" href="#field-settings" aria-label="Permalink to &quot;Field Settings&quot;">​</a></h2><p>When you add a Radio field and expand it in the builder, the following settings are available:</p><h3 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Label</strong></td><td style="text-align:left;">The title displayed above the radio group (e.g., &quot;Choose Processing Speed&quot;).</td></tr><tr><td style="text-align:left;"><strong>Description</strong></td><td style="text-align:left;">Optional help text shown below the field.</td></tr><tr><td style="text-align:left;"><strong>Required</strong></td><td style="text-align:left;">When checked, the customer must select one of the radio options before adding the product to the cart.</td></tr></tbody></table><h3 id="choices-options" tabindex="-1">Choices (Options) <a class="header-anchor" href="#choices-options" aria-label="Permalink to &quot;Choices (Options)&quot;">​</a></h3><p>You must define at least one choice. Each choice has the following columns:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Column</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Label</strong></td><td style="text-align:left;">The text displayed next to the radio button (e.g., &quot;Express Shipping&quot;). The <strong>Value</strong> is automatically generated from the label.</td></tr><tr><td style="text-align:left;"><strong>Price</strong></td><td style="text-align:left;">The numeric amount to add to the product price when this choice is selected. Only visible when Price Type is not &quot;No Price&quot;.</td></tr><tr><td style="text-align:left;"><strong>Price Type</strong></td><td style="text-align:left;">How this choice affects pricing. Options: <strong>No Price</strong>, <strong>Flat Fee</strong>, <strong>Percentage of Base</strong>, or <strong>Formula</strong>. Each choice can have its own independent price type.</td></tr><tr><td style="text-align:left;"><strong>Weight</strong></td><td style="text-align:left;">Additional shipping weight to add when this choice is selected.</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>The layout of radio buttons (vertical stack vs. horizontal row) is controlled by the <strong>Options Orientation</strong> setting in WooCommerce &gt; Settings &gt; OptionBay.</p></div><p>You can add new choices using the <strong>+ Add Choice</strong> button and remove them using the trash icon.</p><h2 id="conditional-logic" tabindex="-1">Conditional Logic <a class="header-anchor" href="#conditional-logic" aria-label="Permalink to &quot;Conditional Logic&quot;">​</a></h2><p>You can show or hide this field based on the value of another field in the same group. For example, show a &quot;Warranty Level&quot; radio group only when the customer checks an &quot;Add Extended Warranty?&quot; checkbox.</p><p>For full details on setting up rules, see the <a href="./../conditional-logic.html">Conditional Logic</a> page.</p>',16)]))}const p=e(n,[["render",l]]);export{u as __pageData,p as default};
